What does this program print?

```cpp
#include <iostream>
#include <stdexcept>
class MyErr : public std::runtime_error {
public:
    MyErr(const std::string& m) : std::runtime_error(m) {}
};
int main() {
    try {
        throw MyErr("custom");
    } catch (const std::runtime_error& e) {
        std::cout << "runtime: " << e.what() << "\n";
    } catch (const MyErr& e) {
        std::cout << "myerr: " << e.what() << "\n";
    }
    return 0;
}
```

